import {
  DateThresholdData,
  DynamicNumericRangeThreshold,
  DynamicNumericThreshold,
  DynamicRangeThreshold,
  DynamicThreshold,
  NumericalThresholdData,
  StaticRangeThreshold,
  StaticThreshold,
} from './thresholds.js';

export function isStatic(
  data: DateThresholdData | NumericalThresholdData,
): data is StaticThreshold {
  return data !== null && !Array.isArray(data) && 'value' in data;
}

export function isStaticRange(
  data: DateThresholdData | NumericalThresholdData,
): data is StaticRangeThreshold {
  return (
    data !== null && !Array.isArray(data) && 'min' in data && 'max' in data
  );
}

export function isDynamic(
  data: DateThresholdData | NumericalThresholdData,
): data is DynamicThreshold {
  return (
    data !== null &&
    Array.isArray(data) &&
    data[0] &&
    'value' in data[0] &&
    'date' in data[0]
  );
}

export function isDynamicNumeric(
  data: DateThresholdData | NumericalThresholdData,
): data is DynamicNumericThreshold {
  return (
    data !== null &&
    Array.isArray(data) &&
    data[0] &&
    'value' in data[0] &&
    'point' in data[0]
  );
}

export function isDynamicRange(
  data: DateThresholdData | NumericalThresholdData,
): data is DynamicRangeThreshold {
  return (
    data !== null &&
    Array.isArray(data) &&
    data[0] &&
    'min' in data[0] &&
    'max' in data[0] &&
    'date' in data[0]
  );
}

export function isDynamicNumericRange(
  data: DateThresholdData | NumericalThresholdData,
): data is DynamicNumericRangeThreshold {
  return (
    data !== null &&
    Array.isArray(data) &&
    data[0] &&
    'min' in data[0] &&
    'max' in data[0] &&
    'point' in data[0]
  );
}

export function isPointThreshold<T extends number | Date>(y0: T, y1: T) {
  return y0.valueOf() === y1.valueOf();
}

export function isBoundedRange(
  data: DateThresholdData | NumericalThresholdData,
): data is StaticThreshold {
  return data !== null && !Array.isArray(data) && 'value' in data;
}
